def build_dsp_from_team(track_keyword, deal_pt, deal_uat):
    """Return DSP tracker rows for the given track keyword using explicit sg/env."""
    rows = []
    for name, track, sg, ssa_module, env in INIT_TEAM:
        if track_keyword not in track:
            continue
        if not sg or not env:          # skip SSA-only or env-less members
            continue
        deal = deal_pt if env == "PT" else deal_uat
        rows.append((name, "DSP", env, sg, deal, ""))
    return rows

def build_ssa_from_team():
    """Return SSA tracker rows for all members with an ssa_module assignment."""
    rows = []
    for name, track, sg, ssa_module, env in INIT_TEAM:
        if not ssa_module:
            continue
        module = ssa_module if ssa_module == "Document Management" else f"SSA/{ssa_module}"
        rows.append((name, module, "", "", "", "", ""))
    return rows

# These three lists are the single source of truth for E2E_Tracker
INIT_DSP_MANUAL = build_dsp_from_team("DSP Manual",     DEAL_PT_MANUAL,  DEAL_UAT_MANUAL)
INIT_DSP_AUTO   = build_dsp_from_team("DSP Automation", DEAL_PT_AUTO,    DEAL_UAT_AUTO)
INIT_SSA        = build_ssa_from_team()

