def fill(hex_color):
    return PatternFill(fill_type="solid", fgColor=hex_color)

def font(bold=False, color="000000", size=10, italic=False):
    return Font(bold=bold, color=color, size=size, italic=italic,
                name="Segoe UI")

def align(h="left", v="center", wrap=False):
    return Alignment(horizontal=h, vertical=v, wrap_text=wrap)

def thin_border():
    s = Side(style="thin", color=C["border"])
    return Border(left=s, right=s, top=s, bottom=s)

def medium_border():
    s = Side(style="medium", color="A0A0A0")
    return Border(left=s, right=s, top=s, bottom=s)

def apply_header_row(ws, row_num, headers, widths, bg_hex, font_color="FFFFFF"):
    """Write a styled header row."""
    for col_idx, (header, width) in enumerate(zip(headers, widths), start=1):
        cell = ws.cell(row=row_num, column=col_idx, value=header)
        cell.fill    = fill(bg_hex)
        cell.font    = font(bold=True, color=font_color, size=10)
        cell.alignment = align(h="center")
        cell.border  = thin_border()
        ws.column_dimensions[get_column_letter(col_idx)].width = width

def apply_data_row(ws, row_num, values, env_val=None, status_col=None):
    """Write a data row with optional env-based banding + status colouring."""
    row_bg = C["pt_band"] if env_val == "PT" else (
             C["uat_band"] if env_val == "UAT" else C["white"])
    for col_idx, val in enumerate(values, start=1):
        cell = ws.cell(row=row_num, column=col_idx, value=val)
        cell.fill      = fill(row_bg)
        cell.font      = font(size=10)
        cell.alignment = align()
        cell.border    = thin_border()

def add_status_validation(ws, col_letter, first_row, last_row):
    """Add dropdown data-validation for the Status column."""
    dv = DataValidation(
        type="list",
        formula1=f'"{",".join(STATUS_OPTIONS)}"',
        showDropDown=False,          # False = show the arrow
        showErrorMessage=True,
        errorTitle="Invalid Status",
        error="Please choose a value from the list.",
    )
    dv.sqref = f"{col_letter}{first_row}:{col_letter}{last_row}"
    ws.add_data_validation(dv)

def add_list_validation(ws, col_letter, first_row, last_row, options):
    dv = DataValidation(
        type="list",
        formula1=f'"{",".join(options)}"',
        showDropDown=False,
        showErrorMessage=True,
        errorTitle="Invalid Value",
        error="Please choose from the dropdown list.",
    )
    dv.sqref = f"{col_letter}{first_row}:{col_letter}{last_row}"
    ws.add_data_validation(dv)

def add_status_conditional_formatting(ws, col_letter, first_row, last_row):
    """Colour-code cells based on status text."""
    rules = [
        ("Passed",               C["passed"],     "276221"),
        ("Completed",            C["completed"],  "276221"),
        ("In Progress",          C["in_progress"],"7D5A00"),
        ("Failed",               C["failed"],     "820014"),
        ("Blocked",              C["blocked"],    "820014"),
        ("Connectivity Failing", C["conn_fail"],  "9E006B"),
        ("Not Started",          C["not_started"],"595959"),
    ]
    cell_range = f"{col_letter}{first_row}:{col_letter}{last_row}"
    for text, bg, fg in rules:
        ds = DifferentialStyle(
            fill=PatternFill(fill_type="solid", fgColor=bg),
            font=Font(bold=True, color=fg, name="Segoe UI"),
        )
        rule = Rule(type="containsText", operator="containsText",
                    text=text, dxf=ds)
        rule.formula = [f'NOT(ISERROR(SEARCH("{text}",{col_letter}{first_row})))']
        ws.conditional_formatting.add(cell_range, rule)

def add_sheet_title(ws, title, subtitle, n_cols):
    """Merge first two rows as a title banner."""
    ws.insert_rows(1, 2)
    ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=n_cols)
    ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=n_cols)

    title_cell = ws["A1"]
    title_cell.value     = title
    title_cell.fill      = fill(C["hdr_dark"])
    title_cell.font      = font(bold=True, color="22C55E", size=14)
    title_cell.alignment = align(h="center")

    sub_cell = ws["A2"]
    sub_cell.value     = subtitle
    sub_cell.fill      = fill("1A1F2E")
    sub_cell.font      = font(italic=True, color="8892A4", size=10)
    sub_cell.alignment = align(h="center")

    ws.row_dimensions[1].height = 28
    ws.row_dimensions[2].height = 18

# ─────────────────────────────────────────────────────────────────────────────
#  SINGLE COMBINED TRACKER SHEET
#  Layout (all in "E2E_Tracker"):
#    Row 1-2  : Workbook title banner
#    ── SECTION 1: DSP MANUAL TESTING ──────────────────────────────────────
#    Row 3    : Section banner (dark blue)
#    Row 4    : PT sub-banner + PT deal ID callout
#    Row 5    : Column headers
#    Row 6…   : PT Manual data rows
#    gap row  : UAT sub-banner + UAT deal ID callout
#    next row : Column headers (repeat for UAT)
#    …        : UAT Manual data rows  + 10 empty buffer rows
#    ── SECTION 2: DSP AUTOMATION TESTING ──────────────────────────────────
#    (same pattern, different deal IDs)
#    ── SECTION 3: SSA / GenAI TESTING ─────────────────────────────────────
#    (SSA-specific columns)
