# Shared column layout for DSP sections
DSP_HEADERS = ["#", "Tester", "Module", "ENV", "SG", "Deal ID",
               "Status", "Comments", "Last Edited By", "Last Edited At", "Notes"]
DSP_WIDTHS  = [4, 28, 10, 7, 9, 14, 22, 28, 22, 18, 28]
N_DSP = len(DSP_HEADERS)

# SSA columns
SSA_HEADERS = ["#", "Tester", "Module / Feature",
               "Deal ID 1", "Deal ID 2", "Deal ID 3", "Deal ID 4",
               "Status", "Last Edited By", "Last Edited At", "Notes"]
SSA_WIDTHS  = [4, 28, 24, 14, 14, 14, 14, 22, 22, 18, 28]
N_SSA = len(SSA_HEADERS)

# Widest column count for merges across all sections
N_COLS = max(N_DSP, N_SSA)  # 11


def _section_banner(ws, row, text, bg_hex):
    """Full-width section title bar."""
    ws.merge_cells(start_row=row, start_column=1,
                   end_row=row, end_column=N_COLS)
    c = ws.cell(row=row, column=1, value=text)
    c.fill      = fill(bg_hex)
    c.font      = font(bold=True, size=12, color="FFFFFF")
    c.alignment = align(h="left")
    ws.row_dimensions[row].height = 24
    return row + 1


def _env_subbanner(ws, row, env_label, deal_id, tag_color):
    """ENV sub-banner with deal ID callout."""
    ws.merge_cells(start_row=row, start_column=1,
                   end_row=row, end_column=N_COLS)
    text = f"  ▶  {env_label}     Deal ID: {deal_id}"
    c = ws.cell(row=row, column=1, value=text)
    c.fill      = fill(tag_color)
    c.font      = font(bold=True, size=11, color="000000")
    c.alignment = align(h="left")
    ws.row_dimensions[row].height = 22
    return row + 1


def _dsp_col_header(ws, row, hdr_bg):
    apply_header_row(ws, row, DSP_HEADERS, DSP_WIDTHS, hdr_bg)
    ws.row_dimensions[row].height = 20
    return row + 1


def _ssa_col_header(ws, row):
    apply_header_row(ws, row, SSA_HEADERS, SSA_WIDTHS, C["hdr_ssa"])
    ws.row_dimensions[row].height = 20
    return row + 1


def _write_dsp_rows(ws, data, row, env_filter, hdr_bg):
    """Write DSP data rows for a given env. Returns (first_data_row, last_data_row, next_free_row)."""
    rows = [(i, r) for i, r in enumerate(data, 1) if r[2] == env_filter]
    first = row
    for local_i, (orig_idx, row_tuple) in enumerate(rows):
        tester, module, env, sg, deal, status = row_tuple
        values = [orig_idx, tester, module, env, sg, deal,
                  status or "", "", "", "", ""]
        apply_data_row(ws, row + local_i, values, env_val=env)
        ws.row_dimensions[row + local_i].height = 18
    last = row + len(rows) - 1
    # Buffer rows
    for buf in range(10):
        r_buf = last + 1 + buf
        apply_data_row(ws, r_buf, [""] * N_DSP, env_val=env_filter)
        ws.row_dimensions[r_buf].height = 16
    return first, last, last + 11


def _write_ssa_rows(ws, row):
    """Write SSA data rows. Returns (first, last, next_free)."""
    first = row
    for i, tup in enumerate(INIT_SSA):
        tester, module, d1, d2, d3, d4, status = tup
        values = [i + 1, tester, module, d1, d2, d3, d4,
                  status or "", "", "", ""]
        apply_data_row(ws, row + i, values)
        ws.row_dimensions[row + i].height = 18
    last = row + len(INIT_SSA) - 1
    for buf in range(10):
        r_buf = last + 1 + buf
        apply_data_row(ws, r_buf, [""] * N_SSA)
        ws.row_dimensions[r_buf].height = 16
    return first, last, last + 11


def build_single_tracker_sheet(wb):
    """Build the single combined E2E_Tracker sheet."""
    ws = wb.create_sheet("E2E_Tracker")
    ws.sheet_view.showGridLines = False
    ws.sheet_properties.tabColor = "22C55E"

    # ── Workbook title (rows 1-2) ──────────────────────────────────────────
    ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=N_COLS)
    t = ws["A1"]
    t.value     = f"DSP & SSA  —  E2E Testing Tracker  |  {MODULE_MONTH}"
    t.fill      = fill(C["hdr_dark"])
    t.font      = font(bold=True, color="22C55E", size=14)
    t.alignment = align(h="center")
    ws.row_dimensions[1].height = 30

    ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=N_COLS)
    s = ws["A2"]
    s.value = (
        f"PT Manual: {DEAL_PT_MANUAL}   |   PT Auto: {DEAL_PT_AUTO}   |   "
        f"UAT Manual: {DEAL_UAT_MANUAL}   |   UAT Auto: {DEAL_UAT_AUTO}"
    )
    s.fill      = fill("1A1F2E")
    s.font      = font(italic=True, color="8892A4", size=10)
    s.alignment = align(h="center")
    ws.row_dimensions[2].height = 18

    # Freeze title rows + first col-header row
    ws.freeze_panes = "A6"

    cur = 3  # current write row

    # ════════════════════════════════════════════════════════════════════════
    # SECTION 1 — DSP MANUAL TESTING
    # ════════════════════════════════════════════════════════════════════════
    cur = _section_banner(ws, cur,
                          "  ◈  SECTION 1 — DSP MANUAL TESTING OPPORTUNITIES",
                          C["hdr_manual"])

    # PT Manual
    cur = _env_subbanner(ws, cur,
                         "PT  (Pre-Testing)", DEAL_PT_MANUAL, "C5E8FF")
    manual_pt_col_hdr = cur
    cur = _dsp_col_header(ws, cur, C["hdr_manual"])
    manual_pt_first, manual_pt_last, cur = _write_dsp_rows(
        ws, INIT_DSP_MANUAL, cur, "PT", C["hdr_manual"])

    cur += 1  # gap row

    # UAT Manual
    cur = _env_subbanner(ws, cur,
                         "UAT  (User Acceptance Testing)", DEAL_UAT_MANUAL, "FFE8B2")
    manual_uat_col_hdr = cur
    cur = _dsp_col_header(ws, cur, C["hdr_manual"])
    manual_uat_first, manual_uat_last, cur = _write_dsp_rows(
        ws, INIT_DSP_MANUAL, cur, "UAT", C["hdr_manual"])

    cur += 2  # gap between sections

    # Add dropdowns + CF for both Manual env blocks
    status_col_dsp = get_column_letter(DSP_HEADERS.index("Status") + 1)  # G
    env_col_dsp    = get_column_letter(DSP_HEADERS.index("ENV")    + 1)  # D
    sg_col_dsp     = get_column_letter(DSP_HEADERS.index("SG")     + 1)  # E

    for first, last in [(manual_pt_first, manual_pt_last + 10),
                        (manual_uat_first, manual_uat_last + 10)]:
        add_list_validation(  ws, env_col_dsp,    first, last, ENV_OPTIONS)
        add_list_validation(  ws, sg_col_dsp,     first, last, SG_OPTIONS)
        add_status_validation(ws, status_col_dsp, first, last)
        add_status_conditional_formatting(ws, status_col_dsp, first, last)

    # ════════════════════════════════════════════════════════════════════════
    # SECTION 2 — DSP AUTOMATION TESTING
    # ════════════════════════════════════════════════════════════════════════
    cur = _section_banner(ws, cur,
                          "  ◈  SECTION 2 — DSP AUTOMATION TESTING OPPORTUNITIES",
                          C["hdr_auto"])

    # PT Auto
    cur = _env_subbanner(ws, cur,
                         "PT  (Pre-Testing)", DEAL_PT_AUTO, "C5E8FF")
    cur = _dsp_col_header(ws, cur, C["hdr_auto"])
    auto_pt_first, auto_pt_last, cur = _write_dsp_rows(
        ws, INIT_DSP_AUTO, cur, "PT", C["hdr_auto"])

    cur += 1

    # UAT Auto
    cur = _env_subbanner(ws, cur,
                         "UAT  (User Acceptance Testing)", DEAL_UAT_AUTO, "FFE8B2")
    cur = _dsp_col_header(ws, cur, C["hdr_auto"])
    auto_uat_first, auto_uat_last, cur = _write_dsp_rows(
        ws, INIT_DSP_AUTO, cur, "UAT", C["hdr_auto"])

    cur += 2

    for first, last in [(auto_pt_first, auto_pt_last + 10),
                        (auto_uat_first, auto_uat_last + 10)]:
        add_list_validation(  ws, env_col_dsp,    first, last, ENV_OPTIONS)
        add_list_validation(  ws, sg_col_dsp,     first, last, SG_OPTIONS)
        add_status_validation(ws, status_col_dsp, first, last)
        add_status_conditional_formatting(ws, status_col_dsp, first, last)

    # ════════════════════════════════════════════════════════════════════════
    # SECTION 3 — SSA / GenAI TESTING
    # ════════════════════════════════════════════════════════════════════════
    cur = _section_banner(ws, cur,
                          "  ◈  SECTION 3 — SSA / GenAI MODULE TESTING",
                          C["hdr_ssa"])

    # Note banner
    ws.merge_cells(start_row=cur, start_column=1,
                   end_row=cur, end_column=N_COLS)
    nb = ws.cell(row=cur, column=1,
                 value="  ⚠  Ensure configuration is applied to ALL deals before marking Passed/Completed.")
    nb.fill      = fill("FFFBE6")
    nb.font      = font(size=10, color="7D5A00", italic=True)
    nb.alignment = align(h="left")
    ws.row_dimensions[cur].height = 20
    cur += 1

    cur = _ssa_col_header(ws, cur)
    ssa_first, ssa_last, cur = _write_ssa_rows(ws, cur)

    status_col_ssa = get_column_letter(SSA_HEADERS.index("Status") + 1)  # H
    add_status_validation(ws, status_col_ssa, ssa_first, ssa_last + 10)
    add_status_conditional_formatting(ws, status_col_ssa, ssa_first, ssa_last + 10)

    # ── Store row anchors on ws for Summary to reference ──────────────────
    ws._tracker_anchors = {
        "manual_pt_first":  manual_pt_first,
        "manual_pt_last":   manual_pt_last + 10,
        "manual_uat_first": manual_uat_first,
        "manual_uat_last":  manual_uat_last + 10,
        "auto_pt_first":    auto_pt_first,
        "auto_pt_last":     auto_pt_last + 10,
        "auto_uat_first":   auto_uat_first,
        "auto_uat_last":    auto_uat_last + 10,
        "ssa_first":        ssa_first,
        "ssa_last":         ssa_last + 10,
        "status_col_dsp":   status_col_dsp,   # G
        "status_col_ssa":   status_col_ssa,   # H
        "env_col":          env_col_dsp,      # D
    }

    return ws

