def build_team_sheet(wb):
    ws = wb.create_sheet("Team_Data")
    ws.sheet_view.showGridLines = False

    headers = ["#", "Name", "Track", "Modules / Assignment", "ENV"]
    widths  = [  5,    20,      30,              40,             8]
    n_cols  = len(headers)

    track_colors = {
        "DSP Manual":     "D6E4FF",
        "DSP Automation": "D9F7BE",
        "SSA":            "EFDBFF",
        "Upload":         "FFF7E6",
    }

    # ── Title banner ──────────────────────────────────────────────────────
    ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=n_cols)
    t = ws["A1"]
    t.value     = f"Team Roster  |  {MODULE_MONTH}"
    t.fill      = fill(C["hdr_dark"])
    t.font      = font(bold=True, color="22C55E", size=14)
    t.alignment = align(h="center")
    ws.row_dimensions[1].height = 28

    ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=n_cols)
    s = ws["A2"]
    s.value     = "Full team assignments for DSP Manual, DSP Automation, SSA, and Upload tracks."
    s.fill      = fill("1A1F2E")
    s.font      = font(italic=True, color="8892A4", size=10)
    s.alignment = align(h="center")
    ws.row_dimensions[2].height = 16

    ws.freeze_panes = "A4"

    def _env_banner(row, label, tag_color):
        ws.merge_cells(start_row=row, start_column=1,
                       end_row=row, end_column=n_cols)
        c = ws.cell(row=row, column=1, value=f"  ▶  {label}")
        c.fill      = fill(tag_color)
        c.font      = font(bold=True, size=11, color="000000")
        c.alignment = align(h="left")
        ws.row_dimensions[row].height = 22
        return row + 1

    def _col_header(row):
        apply_header_row(ws, row, headers, widths, C["hdr_team"])
        ws.row_dimensions[row].height = 20
        return row + 1

    def _write_members(members, start_row, seq_offset=0):
        for i, (name, track, sg, ssa_module, env) in enumerate(members):
            r = start_row + i
            band = next((v for k, v in track_colors.items() if k in track), C["white"])
            # Build a readable assignment string
            if sg and ssa_module:
                assignment = f"{sg} ({env})  /  {ssa_module}"
            elif sg:
                assignment = f"{sg} ({env})" if env else sg
            elif ssa_module:
                assignment = ssa_module
            else:
                assignment = ""
            for col_idx, val in enumerate([seq_offset + i + 1, name, track, assignment, env], start=1):
                cell = ws.cell(row=r, column=col_idx, value=val)
                cell.fill      = fill(band)
                cell.font      = font(size=10)
                cell.alignment = align()
                cell.border    = thin_border()
            ws.row_dimensions[r].height = 18
        return start_row + len(members)

    # ── Split by ENV ───────────────────────────────────────────────────────
    pt_members    = [(n, t, sg, m, e) for n, t, sg, m, e in INIT_TEAM if e == "PT"]
    uat_members   = [(n, t, sg, m, e) for n, t, sg, m, e in INIT_TEAM if e == "UAT"]
    other_members = [(n, t, sg, m, e) for n, t, sg, m, e in INIT_TEAM if e not in ("PT", "UAT")]

    cur = 3

    # PT section
    cur = _env_banner(cur, "PT  —  Pre-Testing", "C5E8FF")
    cur = _col_header(cur)
    cur = _write_members(pt_members, cur, seq_offset=0)

    cur += 1  # gap row

    # UAT section
    cur = _env_banner(cur, "UAT  —  User Acceptance Testing", "FFE8B2")
    cur = _col_header(cur)
    cur = _write_members(uat_members, cur, seq_offset=len(pt_members))

    # Other section (SSA/Upload with no env)
    if other_members:
        cur += 1
        cur = _env_banner(cur, "SSA / No Specific ENV", "EFDBFF")
        cur = _col_header(cur)
        cur = _write_members(other_members, cur, seq_offset=len(pt_members) + len(uat_members))

    ws.sheet_properties.tabColor = "B7860B"
    return ws

# ─────────────────────────────────────────────
#  SUMMARY / DASHBOARD SHEET
#  References the single E2E_Tracker sheet
# ─────────────────────────────────────────────

def build_summary_sheet(wb, tracker_ws):
    """Build Summary_Dashboard using row anchors stored on tracker_ws."""
    a = tracker_ws._tracker_anchors
    s_dsp = a["status_col_dsp"]    # G
    s_ssa = a["status_col_ssa"]    # H
    e_col = a["env_col"]           # D
    sheet = "E2E_Tracker"

    ws = wb.create_sheet("Summary_Dashboard")
    ws.sheet_view.showGridLines = False
    ws.sheet_properties.tabColor = "22C55E"

    # ── Title ──────────────────────────────────────────
    ws.merge_cells("A1:H1")
    t = ws["A1"]
    t.value     = f"DSP & SSA — E2E Testing Summary Dashboard  |  {MODULE_MONTH}"
    t.fill      = fill(C["hdr_dark"])
    t.font      = font(bold=True, color="22C55E", size=15)
    t.alignment = align(h="center")
    ws.row_dimensions[1].height = 32

    ws.merge_cells("A2:H2")
    s = ws["A2"]
    s.value = (
        f"PT Manual: {DEAL_PT_MANUAL}  |  PT Auto: {DEAL_PT_AUTO}  |  "
        f"UAT Manual: {DEAL_UAT_MANUAL}  |  UAT Auto: {DEAL_UAT_AUTO}"
    )
    s.fill      = fill("1A1F2E")
    s.font      = font(italic=True, color="8892A4", size=10)
    s.alignment = align(h="center")
    ws.row_dimensions[2].height = 18

    # ── KPI header ────────────────────────────────────
    kpi_headers = ["Section", "Total", "Passed", "Completed",
                   "In Progress", "Failed/Blocked", "Not Started", "% Done"]
    kpi_widths  = [30, 10, 10, 12, 13, 16, 13, 14]

    KPI_HDR_ROW = 4
    for col_i, (hdr, w) in enumerate(zip(kpi_headers, kpi_widths), start=1):
        cell = ws.cell(row=KPI_HDR_ROW, column=col_i, value=hdr)
        cell.fill      = fill(C["hdr_summary"])
        cell.font      = font(bold=True, color="FFFFFF", size=10)
        cell.alignment = align(h="center")
        cell.border    = thin_border()
        ws.column_dimensions[get_column_letter(col_i)].width = w
    ws.row_dimensions[KPI_HDR_ROW].height = 22

    # ── KPI rows — COUNTIFS into E2E_Tracker ──────────
    # Each entry: (label, s_col, e_col_or_None, env_filter_or_None, first_row, last_row)
    kpi_defs = [
        ("DSP Manual — PT",  s_dsp, e_col, "PT",  a["manual_pt_first"],  a["manual_pt_last"]),
        ("DSP Manual — UAT", s_dsp, e_col, "UAT", a["manual_uat_first"], a["manual_uat_last"]),
        ("DSP Auto — PT",    s_dsp, e_col, "PT",  a["auto_pt_first"],    a["auto_pt_last"]),
        ("DSP Auto — UAT",   s_dsp, e_col, "UAT", a["auto_uat_first"],   a["auto_uat_last"]),
        ("SSA / GenAI",      s_ssa, None,  None,  a["ssa_first"],        a["ssa_last"]),
    ]

    def cif(sc, f, l, status_val, ec=None, env_val=None):
        """Build a COUNTIFS formula string."""
        sc_range = f"'{sheet}'!{sc}{f}:{sc}{l}"
        if ec and env_val:
            ec_range = f"'{sheet}'!{ec}{f}:{ec}{l}"
            if status_val:
                return (f"=COUNTIFS({ec_range},\"{env_val}\","
                        f"{sc_range},\"{status_val}\")")
            else:
                # total: count non-blank env rows
                return f"=COUNTIFS({ec_range},\"{env_val}\")"
        else:
            if status_val:
                return f"=COUNTIF({sc_range},\"{status_val}\")"
            else:
                return f"=COUNTA({sc_range})"

    for offset, (label, sc, ec, env_val, first, last) in enumerate(kpi_defs):
        r = KPI_HDR_ROW + 1 + offset
        ws.row_dimensions[r].height = 20
        row_bg = C["light_gray"] if offset % 2 == 0 else C["white"]

        # Label
        lc = ws.cell(row=r, column=1, value=label)
        lc.fill = fill(row_bg); lc.font = font(bold=True, size=10)
        lc.border = thin_border(); lc.alignment = align()

        total_f     = cif(sc, first, last, None,             ec, env_val)
        passed_f    = cif(sc, first, last, "Passed",         ec, env_val)
        completed_f = cif(sc, first, last, "Completed",      ec, env_val)
        inp_f       = cif(sc, first, last, "In Progress",    ec, env_val)
        # Failed/Blocked requires two COUNTIFS summed
        if ec and env_val:
            ec_r = f"'{sheet}'!{ec}{first}:{ec}{last}"
            sc_r = f"'{sheet}'!{sc}{first}:{sc}{last}"
            failed_f = (
                f"=COUNTIFS({ec_r},\"{env_val}\",{sc_r},\"Failed\")"
                f"+COUNTIFS({ec_r},\"{env_val}\",{sc_r},\"Blocked\")"
                f"+COUNTIFS({ec_r},\"{env_val}\",{sc_r},\"Connectivity Failing\")"
            )
            notst_f = (
                f"=COUNTIFS({ec_r},\"{env_val}\",{sc_r},\"\")"
                f"+COUNTIFS({ec_r},\"{env_val}\",{sc_r},\"Not Started\")"
            )
        else:
            sc_r = f"'{sheet}'!{sc}{first}:{sc}{last}"
            failed_f = (
                f"=COUNTIF({sc_r},\"Failed\")"
                f"+COUNTIF({sc_r},\"Blocked\")"
                f"+COUNTIF({sc_r},\"Connectivity Failing\")"
            )
            notst_f = (
                f"=COUNTIF({sc_r},\"\")"
                f"+COUNTIF({sc_r},\"Not Started\")"
            )

        total_ref = f"B{r}"
        pct_f = f"=IF({total_ref}=0,0,ROUND((C{r}+D{r})/{total_ref}*100,1))"

        col_data = [
            (total_f,     None),
            (passed_f,    C["passed"]),
            (completed_f, C["completed"]),
            (inp_f,       C["in_progress"]),
            (failed_f,    C["failed"]),
            (notst_f,     C["not_started"]),
            (pct_f,       "E9F5E9"),
        ]
        for col_i, (formula, bg) in enumerate(col_data, start=2):
            c = ws.cell(row=r, column=col_i, value=formula)
            c.fill      = fill(bg if bg else row_bg)
            c.font      = font(size=10, bold=(col_i == 8), color=("276221" if col_i == 8 else "000000"))
            c.alignment = align(h="center")
            c.border    = thin_border()
        ws.cell(row=r, column=8).number_format = '0.0"%"'

    # Data-bar on % Done (col H)
    pct_range = f"H{KPI_HDR_ROW + 1}:H{KPI_HDR_ROW + len(kpi_defs)}"
    ws.conditional_formatting.add(
        pct_range,
        DataBarRule(start_type="num", start_value=0,
                    end_type="num", end_value=100,
                    color="22C55E"),
    )

    # ── Legend ────────────────────────────────────────
    leg_row = KPI_HDR_ROW + len(kpi_defs) + 3
    ws.merge_cells(f"A{leg_row}:H{leg_row}")
    lh = ws[f"A{leg_row}"]
    lh.value = "Status Colour Legend"
    lh.fill  = fill(C["hdr_dark"]); lh.font = font(bold=True, color="FFFFFF", size=11)
    lh.alignment = align(h="center")
    ws.row_dimensions[leg_row].height = 22

    legend_items = [
        ("Passed",               C["passed"],     "276221"),
        ("Completed",            C["completed"],  "276221"),
        ("In Progress",          C["in_progress"],"7D5A00"),
        ("Failed",               C["failed"],     "820014"),
        ("Blocked",              C["blocked"],    "820014"),
        ("Connectivity Failing", C["conn_fail"],  "9E006B"),
        ("Not Started",          C["not_started"],"595959"),
    ]
    for i, (lbl, bg, fg) in enumerate(legend_items):
        col = (i % 4) * 2 + 1
        row = leg_row + 1 + (i // 4)
        c = ws.cell(row=row, column=col, value=lbl)
        c.fill = fill(bg); c.font = font(bold=True, color=fg, size=10)
        c.alignment = align(h="center"); c.border = thin_border()
        ws.merge_cells(start_row=row, start_column=col,
                       end_row=row, end_column=col + 1)
        ws.row_dimensions[row].height = 20

    ws.freeze_panes = "A4"
    return ws

# ─────────────────────────────────────────────
#  INSTRUCTIONS SHEET
# ─────────────────────────────────────────────

def build_instructions_sheet(wb):
    ws = wb.create_sheet("How_To_Use")
    ws.sheet_view.showGridLines = False
    ws.sheet_properties.tabColor = "F59E0B"
    ws.column_dimensions["A"].width = 80

    lines = [
        ("DSP & SSA E2E Tracker — How To Use", "title"),
        ("", "blank"),
        ("SHEET OVERVIEW", "section"),
        ("• E2E_Tracker       — Single combined sheet: DSP Manual (PT+UAT), DSP Auto (PT+UAT), SSA/GenAI.", "body"),
        ("• Summary_Dashboard — Live KPI table with COUNTIFS formulas + % Done progress bars.", "body"),
        ("• Team_Data         — Reference roster of all team members and their assignments.", "body"),
        ("", "blank"),
        ("DEAL IDs — MAY 2026 RELEASE", "section"),
        (f"  PT  Manual  → {DEAL_PT_MANUAL}", "body"),
        (f"  PT  Auto    → {DEAL_PT_AUTO}", "body"),
        (f"  UAT Manual  → {DEAL_UAT_MANUAL}", "body"),
        (f"  UAT Auto    → {DEAL_UAT_AUTO}", "body"),
        ("", "blank"),
        ("EDITING DATA", "section"),
        ("• Scroll down the E2E_Tracker sheet — sections are clearly labelled with dark banners.", "body"),
        ("• Status, ENV, and SG columns have dropdown lists — click the cell to see the arrow.", "body"),
        ("• Statuses: Not Started / In Progress / Completed / Passed / Failed / Blocked / Connectivity Failing", "body"),
        ("• ENV dropdown: PT (Pre-Testing), UAT (User Acceptance Testing).", "body"),
        ("• SG dropdown: SI, AMS, BPMS, IMS.", "body"),
        ("• 10 empty buffer rows are pre-styled at the bottom of each env block for new entries.", "body"),
        ("", "blank"),
        ("COLOUR CODING", "section"),
        ("• PT rows  — Light blue background.", "body"),
        ("• UAT rows — Light amber background.", "body"),
        ("• Status cells are automatically colour-coded via conditional formatting.", "body"),
        ("", "blank"),
        ("SUMMARY DASHBOARD", "section"),
        ("• Uses COUNTIFS formulas pointing at exact row ranges in E2E_Tracker.", "body"),
        ("• % Done = (Passed + Completed) / Total × 100, shown with a green data-bar.", "body"),
        ("• Summary refreshes automatically — no manual update needed.", "body"),
        ("", "blank"),
        ("TIPS", "section"),
        ("• Use Ctrl+F to search within the E2E_Tracker sheet.", "body"),
        ("• Don't rename the E2E_Tracker sheet — the Summary formulas reference it by name.", "body"),
        ("• Save as .xlsx to preserve all formatting, dropdowns, and conditional formatting.", "body"),
    ]

    style_map = {
        "title":   (C["hdr_dark"], True, "22C55E", 16),
        "section": (C["hdr_summary"], True, "FFFFFF", 11),
        "body":    (C["white"], False, "000000", 10),
        "blank":   (C["white"], False, "000000", 10),
    }

    for row_i, (text, style) in enumerate(lines, start=1):
        cell = ws.cell(row=row_i, column=1, value=text)
        bg, bold, fg, size = style_map[style]
        cell.fill      = fill(bg)
        cell.font      = font(bold=bold, color=fg, size=size)
        cell.alignment = align(h="left" if style != "title" else "center", wrap=True)
        ws.row_dimensions[row_i].height = 22 if style == "title" else 18

    return ws

# ─────────────────────────────────────────────
#  MAIN
# ─────────────────────────────────────────────

def main():
    wb = Workbook()
    wb.remove(wb.active)   # remove default blank sheet

    print(f"Building workbook: {FILE_NAME}")

    # 1. Build tracker first (populates _tracker_anchors)
    tracker_ws = build_single_tracker_sheet(wb)

    # 2. Summary references tracker anchors
    build_summary_sheet(wb, tracker_ws)

    # 3. Supporting sheets
    build_team_sheet(wb)
    build_instructions_sheet(wb)

    # Open on Summary by default
    wb.active = wb["Summary_Dashboard"]

    out_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), FILE_NAME)
    wb.save(out_path)
    print(f"✓  Saved → {out_path}")
    print()
    print("  Sheets created:")
    for s in wb.sheetnames:
        print(f"    • {s}")

if __name__ == "__main__":
    main()
